/** SLA: 受付から14営業日（≒14日）以内に初動審査。 */
export const SLA_DAYS = 14;

/**
 * 市民税・県民税（個人住民税）の簡易計算ロジック。
 *
 * 実務の所得割・均等割の構造を模した教育用モデル（実際の税額とは細部が異なる）。
 * 給与所得控除はおおまかな簡易式、所得割の税率は政令市の標準（市民税8% / 県民税2%）、
 * 均等割は市民税3,500円 + 県民税2,000円（森林環境税相当の上乗せ込み）で固定。
 */

export interface IncomeInputs {
  /** 給与収入（額面） */
  salary: number;
  /** 事業収入 */
  business: number;
  /** その他の所得（雑所得など、収入＝所得とみなす簡易扱い） */
  other: number;
}

export interface DeductionInputs {
  /** 社会保険料控除 */
  socialInsurance: number;
  /** 扶養人数（一般扶養 1人あたり33万円） */
  dependents: number;
  /** 生命保険料控除 */
  lifeInsurance: number;
  /** 医療費控除 */
  medical: number;
}

/** 各控除エントリ（チェックリスト表示用） */
export interface DeductionEntry {
  id: string;
  label: string;
  amount: number;
  /** 自動適用（基礎控除など）か、申告由来か */
  source: "自動" | "申告";
  note?: string;
}

export interface TaxResult {
  /** 合計所得金額 */
  totalIncome: number;
  /** 所得控除の合計 */
  totalDeduction: number;
  /** 課税所得金額（1000円未満切り捨て） */
  taxableIncome: number;
  /** 市民税 所得割 */
  cityIncomeTax: number;
  /** 県民税 所得割 */
  prefIncomeTax: number;
  /** 均等割（市民税＋県民税） */
  perCapita: number;
  /** 年税額 合計（100円未満切り捨て） */
  total: number;
  deductions: DeductionEntry[];
}

const BASIC_DEDUCTION = 430_000; // 基礎控除（合計所得2,400万円以下）
const DEPENDENT_DEDUCTION = 330_000; // 一般扶養控除 1人あたり
const CITY_RATE = 0.08; // 市民税 所得割 標準税率
const PREF_RATE = 0.02; // 県民税 所得割 標準税率
const CITY_PER_CAPITA = 3_500; // 市民税 均等割
const PREF_PER_CAPITA = 2_000; // 県民税 均等割（森林環境税相当込み）

/** 給与所得控除（令和の簡易式に近い近似）。 */
export function salaryDeduction(salary: number): number {
  if (salary <= 0) return 0;
  if (salary <= 1_625_000) return 550_000;
  if (salary <= 1_800_000) return Math.floor(salary * 0.4) - 100_000;
  if (salary <= 3_600_000) return Math.floor(salary * 0.3) + 80_000;
  if (salary <= 6_600_000) return Math.floor(salary * 0.2) + 440_000;
  if (salary <= 8_500_000) return Math.floor(salary * 0.1) + 1_100_000;
  return 1_950_000;
}

export function computeTax(income: IncomeInputs, deduction: DeductionInputs): TaxResult {
  const salaryIncome = Math.max(0, income.salary - salaryDeduction(income.salary));
  const totalIncome = salaryIncome + income.business + income.other;

  const dependentDeduction = deduction.dependents * DEPENDENT_DEDUCTION;

  const deductions: DeductionEntry[] = [
    { id: "basic", label: "基礎控除", amount: BASIC_DEDUCTION, source: "自動", note: "合計所得2,400万円以下" },
    {
      id: "social",
      label: "社会保険料控除",
      amount: deduction.socialInsurance,
      source: "申告",
      note: "支払額の全額",
    },
    {
      id: "dependent",
      label: `扶養控除（${deduction.dependents}人）`,
      amount: dependentDeduction,
      source: "申告",
      note: "一般扶養 1人 33万円",
    },
    { id: "life", label: "生命保険料控除", amount: deduction.lifeInsurance, source: "申告" },
    { id: "medical", label: "医療費控除", amount: deduction.medical, source: "申告" },
  ];

  const totalDeduction = deductions.reduce((sum, d) => sum + d.amount, 0);

  // 課税所得（1,000円未満切り捨て）
  const taxableIncomeRaw = Math.max(0, totalIncome - totalDeduction);
  const taxableIncome = Math.floor(taxableIncomeRaw / 1000) * 1000;

  const cityIncomeTax = Math.floor(taxableIncome * CITY_RATE);
  const prefIncomeTax = Math.floor(taxableIncome * PREF_RATE);
  const perCapita = taxableIncome > 0 || totalIncome > 0 ? CITY_PER_CAPITA + PREF_PER_CAPITA : 0;

  // 年税額（100円未満切り捨て）
  const totalRaw = cityIncomeTax + prefIncomeTax + perCapita;
  const total = Math.floor(totalRaw / 100) * 100;

  return {
    totalIncome,
    totalDeduction,
    taxableIncome,
    cityIncomeTax,
    prefIncomeTax,
    perCapita,
    total,
    deductions,
  };
}

export type InstallmentStatus = "納付済" | "未納" | "延滞";

export interface Installment {
  /** 第N期 */
  term: number;
  label: string;
  /** 納期限 (ISO) */
  dueDate: string;
  amount: number;
  status: InstallmentStatus;
  /** 納付済の場合の納付日 (ISO) */
  paidDate?: string;
}

/** 年税額を期別（第1期〜第4期）へ按分。第1期に端数を寄せる。 */
export function splitInstallments(
  total: number,
  dueDates: string[],
  statuses: InstallmentStatus[],
  paidDates: (string | undefined)[]
): Installment[] {
  const per = Math.floor(total / 4 / 100) * 100;
  const remainder = total - per * 4;
  return dueDates.map((dueDate, i) => ({
    term: i + 1,
    label: `第${["", "1", "2", "3", "4"][i + 1]}期`,
    dueDate,
    amount: i === 0 ? per + remainder : per,
    status: statuses[i],
    paidDate: paidDates[i],
  }));
}

/** 納期限からの経過日数（超過していなければ0）。 */
export function daysOverdue(dueDate: string, asOf: string): number {
  const due = new Date(dueDate).getTime();
  const now = new Date(asOf).getTime();
  if (now <= due) return 0;
  return Math.floor((now - due) / 86_400_000);
}

/** 延滞金の概算（年8.7%の日割り・簡易）。延滞分のみ。 */
export function lateFee(amount: number, dueDate: string, asOf: string): number {
  const due = new Date(dueDate).getTime();
  const now = new Date(asOf).getTime();
  if (now <= due) return 0;
  const days = Math.floor((now - due) / 86_400_000);
  const fee = (amount * 0.087 * days) / 365;
  // 100円未満切り捨て、1,000円未満は徴収しない実務に寄せる
  const floored = Math.floor(fee / 100) * 100;
  return floored < 1000 ? 0 : floored;
}

"use client";

import * as React from "react";
import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  CardFooter,
  Button,
  Badge,
  Separator,
  Statistic,
  CurrencyInput,
  NumberInput,
  Select,
  Progress,
  Meter,
  ReferenceValue,
  MetadataList,
  DataTable,
  SignedRecord,
  CoSign,
  CoSignBadge,
  Alert,
  AlertTitle,
  AlertDescription,
  Dialog,
  DialogTrigger,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  DialogClose,
  formatCurrency,
  type ColumnDef,
  type SignedRecordValue,
  type CoSignValue,
} from "@gunjo/ui";
import {
  IconAlertTriangle,
  IconCircleCheck,
  IconClockExclamation,
  IconCircleDot,
  IconFileInvoice,
  IconReceiptTax,
  IconUserCheck,
} from "@tabler/icons-react";

import {
  computeTax,
  splitInstallments,
  lateFee,
  daysOverdue,
  type IncomeInputs,
  type DeductionInputs,
  type Installment,
  type InstallmentStatus,
} from "./tax-calc";
import { filings, SLA_DAYS, type FilingRow } from "./data";

const yen = (n: number) => formatCurrency(n, { maximumFractionDigits: 0 });

/** 評価基準日（延滞判定の「今日」）。決定的なビルドのため固定。 */
const AS_OF = "2024-11-15";

/* ────────────────────────────────────────────────────────────────────────
   納付状態のステータスピル（色だけに依存しない: アイコン + テキストラベル）
   ──────────────────────────────────────────────────────────────────────── */
function InstallmentStatusBadge({ status }: { status: InstallmentStatus }) {
  if (status === "納付済") {
    return (
      <Badge variant="success" icon={<IconCircleCheck />}>
        納付済
      </Badge>
    );
  }
  if (status === "延滞") {
    return (
      <Badge variant="destructive" icon={<IconAlertTriangle />}>
        延滞
      </Badge>
    );
  }
  return (
    <Badge variant="warning" icon={<IconCircleDot />}>
      未納
    </Badge>
  );
}

export default function TaxFilingScreen() {
  /* ── 申告内容（編集すると税額がライブ再計算される） ── */
  const [income, setIncome] = React.useState<IncomeInputs>({
    salary: 5_200_000,
    business: 0,
    other: 120_000,
  });
  const [deduction, setDeduction] = React.useState<DeductionInputs>({
    socialInsurance: 742_000,
    dependents: 1,
    lifeInsurance: 40_000,
    medical: 0,
  });

  const tax = React.useMemo(() => computeTax(income, deduction), [income, deduction]);

  /* ── 期別の納付状況（第1期延滞のシナリオ） ── */
  const installments = React.useMemo<Installment[]>(
    () =>
      splitInstallments(
        tax.total,
        ["2024-06-30", "2024-08-31", "2024-10-31", "2025-01-31"],
        ["納付済", "延滞", "延滞", "未納"],
        ["2024-06-20", undefined, undefined, undefined]
      ),
    [tax.total]
  );

  const paidTotal = installments
    .filter((i) => i.status === "納付済")
    .reduce((s, i) => s + i.amount, 0);
  const overdue = installments.filter((i) => i.status === "延滞");
  const overdueAmount = overdue.reduce((s, i) => s + i.amount, 0);
  const totalLateFee = overdue.reduce((s, i) => s + lateFee(i.amount, i.dueDate, AS_OF), 0);

  /* ── 確定（署名）と納税通知書の発付 ── */
  const officerId = "税務 太郎（職員番号 1042）";
  const [record, setRecord] = React.useState<SignedRecordValue>({
    status: "draft",
    addenda: [],
  });
  const [coSign, setCoSign] = React.useState<CoSignValue | undefined>(undefined);
  const [noticeIssued, setNoticeIssued] = React.useState(false);
  const isFinalized = record.status === "signed";

  /* ── 申告一覧（キュー）の列定義 ── */
  const columns = React.useMemo<ColumnDef<FilingRow>[]>(
    () => [
      {
        accessorKey: "resident",
        header: "住民 / 整理番号",
        cell: ({ row }) => (
          <div className="min-w-0">
            <div className="truncate font-medium text-foreground">{row.original.resident}</div>
            <div className="truncate text-xs text-muted-foreground tabular-nums">
              {row.original.kana}・{row.original.id}
            </div>
          </div>
        ),
      },
      {
        accessorKey: "category",
        header: "申告区分",
        cell: ({ row }) =>
          row.original.category === "未申告" ? (
            <Badge variant="destructive" icon={<IconAlertTriangle />}>
              未申告
            </Badge>
          ) : (
            <Badge variant="outline">{row.original.category}</Badge>
          ),
      },
      {
        accessorKey: "filedAt",
        header: "申告日",
        cell: ({ row }) => (
          <span className="tabular-nums text-sm text-muted-foreground">
            {row.original.filedAt ?? "—"}
          </span>
        ),
      },
      {
        accessorKey: "taxAmount",
        header: "年税額",
        cell: ({ row }) => (
          <span className="tabular-nums">
            {row.original.taxAmount > 0 ? yen(row.original.taxAmount) : "—"}
          </span>
        ),
      },
      {
        id: "payment",
        header: "納付状況",
        cell: ({ row }) => {
          const s = row.original.installmentStatuses;
          if (s.includes("延滞")) {
            return (
              <Badge variant="destructive" icon={<IconAlertTriangle />}>
                延滞あり
              </Badge>
            );
          }
          const paid = s.filter((x) => x === "納付済").length;
          if (paid === s.length && row.original.taxAmount > 0) {
            return (
              <Badge variant="success" icon={<IconCircleCheck />}>
                完納
              </Badge>
            );
          }
          return (
            <span className="text-xs tabular-nums text-muted-foreground">
              {paid}/{s.length} 期 納付
            </span>
          );
        },
      },
      {
        id: "sla",
        header: "SLA / 状態",
        cell: ({ row }) => {
          const r = row.original;
          if (r.category === "未申告") {
            return (
              <Badge variant="destructive" icon={<IconClockExclamation />}>
                督促対象
              </Badge>
            );
          }
          // 未審査・審査中で SLA 超過なら警告
          if (r.stage !== "確定済" && r.ageDays > SLA_DAYS) {
            return (
              <Badge variant="warning" icon={<IconClockExclamation />}>
                SLA超過 +{r.ageDays - SLA_DAYS}日
              </Badge>
            );
          }
          if (r.stage === "確定済") {
            return (
              <Badge variant="success" icon={<IconCircleCheck />}>
                確定済
              </Badge>
            );
          }
          return <span className="text-xs text-muted-foreground">受付 {r.ageDays}日</span>;
        },
      },
    ],
    []
  );

  return (
    <main className="mx-auto w-full max-w-6xl px-4 py-6 sm:px-6 sm:py-8">
      {/* ── ページヘッダ ── */}
      <header className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
        <div className="flex min-w-0 items-start gap-3">
          <span
            className="mt-0.5 flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary-subtle text-primary-subtle-foreground"
            aria-hidden="true"
          >
            <IconReceiptTax className="h-5 w-5" />
          </span>
          <div className="min-w-0">
            <h1 className="text-2xl font-bold tracking-tight text-foreground">
              市民税・県民税 申告／納税管理
            </h1>
            <p className="mt-1 text-sm text-muted-foreground">
              令和6年度（2024年度）・税務課 住民税担当　担当者: {officerId}
            </p>
          </div>
        </div>
        <div className="flex shrink-0 items-center gap-2">
          {isFinalized ? (
            <Badge variant="success" icon={<IconCircleCheck />}>
              申告確定済
            </Badge>
          ) : (
            <Badge variant="info">審査中</Badge>
          )}
          <CoSignBadge value={coSign} />
        </div>
      </header>

      <Separator className="my-6" />

      {/* ── 審査対象住民の見出し ── */}
      <section aria-labelledby="case-heading" className="mb-6">
        <div className="flex flex-wrap items-center justify-between gap-2">
          <h2 id="case-heading" className="text-lg font-semibold text-foreground">
            審査中の申告: 佐藤 健一（R-2024-0481）
          </h2>
          <Badge variant="outline">確定申告・令和6年3月12日 受付</Badge>
        </div>
      </section>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">
        {/* ════════ 左: 申告内容 / 税額計算 ════════ */}
        <div className="flex flex-col gap-6 lg:col-span-2">
          <Card>
            <CardHeader>
              <CardTitle as="h2">申告内容 / 税額計算</CardTitle>
              <CardDescription>
                収入・控除を編集すると、課税所得と税額（市民税・県民税・均等割）が即時に再計算されます。
              </CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-6">
              {/* 収入 */}
              <fieldset className="flex flex-col gap-3">
                <legend className="mb-1 text-sm font-semibold text-foreground">収入</legend>
                <div className="grid grid-cols-1 gap-4 sm:grid-cols-3">
                  <CurrencyInput
                    label="給与収入（額面）"
                    value={income.salary}
                    min={0}
                    onValueChange={(v) => setIncome((s) => ({ ...s, salary: v ?? 0 }))}
                  />
                  <CurrencyInput
                    label="事業収入"
                    value={income.business}
                    min={0}
                    onValueChange={(v) => setIncome((s) => ({ ...s, business: v ?? 0 }))}
                  />
                  <CurrencyInput
                    label="その他の所得"
                    value={income.other}
                    min={0}
                    onValueChange={(v) => setIncome((s) => ({ ...s, other: v ?? 0 }))}
                  />
                </div>
              </fieldset>

              {/* 控除 */}
              <fieldset className="flex flex-col gap-3">
                <legend className="mb-1 text-sm font-semibold text-foreground">所得控除</legend>
                <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
                  <CurrencyInput
                    label="社会保険料控除"
                    value={deduction.socialInsurance}
                    min={0}
                    onValueChange={(v) =>
                      setDeduction((s) => ({ ...s, socialInsurance: v ?? 0 }))
                    }
                  />
                  <NumberInput
                    label="扶養人数（一般扶養）"
                    layout="stepper"
                    value={deduction.dependents}
                    min={0}
                    max={10}
                    description="1人あたり 33万円を控除"
                    onValueChange={(v) => setDeduction((s) => ({ ...s, dependents: v }))}
                  />
                  <CurrencyInput
                    label="生命保険料控除"
                    value={deduction.lifeInsurance}
                    min={0}
                    max={70_000}
                    onValueChange={(v) =>
                      setDeduction((s) => ({ ...s, lifeInsurance: v ?? 0 }))
                    }
                  />
                  <CurrencyInput
                    label="医療費控除"
                    value={deduction.medical}
                    min={0}
                    onValueChange={(v) => setDeduction((s) => ({ ...s, medical: v ?? 0 }))}
                  />
                </div>
              </fieldset>

              <Separator />

              {/* 課税所得 → 税額の内訳 */}
              <div className="flex flex-col gap-4">
                <h3 className="text-sm font-semibold text-foreground">課税標準・税額の内訳</h3>
                <div className="grid grid-cols-2 gap-3 sm:grid-cols-3">
                  <Statistic label="合計所得金額" value={yen(tax.totalIncome)} />
                  <Statistic label="所得控除 合計" value={yen(tax.totalDeduction)} />
                  <Statistic
                    label="課税所得金額"
                    value={yen(tax.taxableIncome)}
                    hint="1,000円未満切り捨て"
                  />
                </div>

                <dl className="rounded-lg border border-border bg-muted/30 p-4">
                  <div className="flex items-center justify-between py-1.5 text-sm">
                    <dt className="text-muted-foreground">市民税 所得割（8%）</dt>
                    <dd className="font-medium tabular-nums">{yen(tax.cityIncomeTax)}</dd>
                  </div>
                  <div className="flex items-center justify-between py-1.5 text-sm">
                    <dt className="text-muted-foreground">県民税 所得割（2%）</dt>
                    <dd className="font-medium tabular-nums">{yen(tax.prefIncomeTax)}</dd>
                  </div>
                  <div className="flex items-center justify-between py-1.5 text-sm">
                    <dt className="text-muted-foreground">
                      均等割（市3,500円＋県2,000円）
                    </dt>
                    <dd className="font-medium tabular-nums">{yen(tax.perCapita)}</dd>
                  </div>
                  <Separator className="my-2" />
                  <div className="flex items-center justify-between py-1">
                    <dt className="text-base font-semibold text-foreground">年税額 合計</dt>
                    <dd className="text-xl font-bold tabular-nums text-foreground">
                      {yen(tax.total)}
                      <span className="ml-1 text-xs font-normal text-muted-foreground">
                        / 年
                      </span>
                    </dd>
                  </div>
                </dl>
              </div>
            </CardContent>
          </Card>

          {/* ════════ 控除チェック ════════ */}
          <Card>
            <CardHeader>
              <CardTitle as="h2">控除チェック</CardTitle>
              <CardDescription>適用された所得控除の内訳と金額。</CardDescription>
            </CardHeader>
            <CardContent>
              <MetadataList
                layout="horizontal"
                items={tax.deductions.map((d) => ({
                  label: (
                    <span className="inline-flex items-center gap-2">
                      {d.label}
                      <Badge variant={d.source === "自動" ? "secondary" : "outline"}>
                        {d.source}
                      </Badge>
                    </span>
                  ),
                  value: <span className="tabular-nums">{yen(d.amount)}</span>,
                  description: d.note,
                }))}
              />
            </CardContent>
          </Card>
        </div>

        {/* ════════ 右: 納付状況 ════════ */}
        <div className="flex flex-col gap-6">
          <Card>
            <CardHeader>
              <CardTitle as="h2">納付状況</CardTitle>
              <CardDescription>期別（第1期〜第4期）の納期・金額・状態。</CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-5">
              {/* 延滞の明示的な警告（色だけに依存しない） */}
              {overdue.length > 0 ? (
                <Alert variant="destructive">
                  <IconAlertTriangle aria-hidden="true" />
                  <AlertTitle as="h3">延滞が発生しています</AlertTitle>
                  <AlertDescription>
                    {overdue.map((i) => i.label).join("・")}（計 {yen(overdueAmount)}）が納期限を
                    経過しています。延滞金 概算 {yen(totalLateFee)} を含め督促状の発付対象です。
                  </AlertDescription>
                </Alert>
              ) : null}

              {/* 納付進捗 */}
              <div className="flex flex-col gap-2">
                <div className="flex items-baseline justify-between text-sm">
                  <span className="font-medium text-foreground">納付進捗</span>
                  <span className="tabular-nums text-muted-foreground">
                    {yen(paidTotal)} / {yen(tax.total)}
                  </span>
                </div>
                <Progress
                  value={paidTotal}
                  max={tax.total || 1}
                  tone="success"
                  label="納付済み額"
                  valueText={`年税額 ${yen(tax.total)} のうち ${yen(paidTotal)} を納付済み`}
                />
              </div>

              <Separator />

              {/* 期別の内訳 */}
              <ul className="flex flex-col gap-3">
                {installments.map((inst) => {
                  const fee = lateFee(inst.amount, inst.dueDate, AS_OF);
                  return (
                    <li
                      key={inst.term}
                      className="flex flex-col gap-1.5 rounded-lg border border-border p-3"
                    >
                      <div className="flex items-center justify-between gap-2">
                        <span className="font-medium text-foreground">{inst.label}</span>
                        <InstallmentStatusBadge status={inst.status} />
                      </div>
                      <div className="flex items-center justify-between text-sm">
                        <span className="text-muted-foreground">
                          納期限{" "}
                          <span className="tabular-nums text-foreground">{inst.dueDate}</span>
                        </span>
                        <span className="font-medium tabular-nums">{yen(inst.amount)}</span>
                      </div>
                      {inst.paidDate ? (
                        <p className="text-xs text-muted-foreground tabular-nums">
                          納付日 {inst.paidDate}
                        </p>
                      ) : null}
                      {inst.status === "延滞" ? (
                        <div className="flex flex-col gap-1 border-t border-border/60 pt-1.5 text-xs">
                          <div className="flex items-center justify-between">
                            <span className="text-muted-foreground">納期限超過</span>
                            {/* ReferenceValue: 経過日数を閾値で判定し、色だけに
                                依存しないフラグチップ（HH）+ sr-only ラベルで
                                「延滞」を伝える（延滞金が¥0でも延滞は明示される）。 */}
                            <ReferenceValue
                              value={daysOverdue(inst.dueDate, AS_OF)}
                              range={{ criticalHigh: 1 }}
                              unit="日"
                              size="inline"
                              labels={{ "critical-high": "延滞中" }}
                              showLabel
                            />
                          </div>
                          <div className="flex items-center justify-between">
                            <span className="text-muted-foreground">延滞金 概算</span>
                            <span className="font-medium tabular-nums text-destructive">
                              {fee > 0 ? yen(fee) : "¥0（1,000円未満不徴収）"}
                            </span>
                          </div>
                        </div>
                      ) : null}
                    </li>
                  );
                })}
              </ul>

              {/* 当年度の延滞負荷メーター（target=0 を基準に延滞ゼロが理想） */}
              <div className="flex flex-col gap-1.5">
                <span className="text-sm font-medium text-foreground">延滞額（対 年税額）</span>
                <Meter
                  value={overdueAmount}
                  max={tax.total || 1}
                  label="延滞額の年税額に占める割合"
                  thresholds={{ warning: 0.01, over: 0.25 }}
                  unit="円"
                  valueText={`延滞 ${yen(overdueAmount)} / 年税額 ${yen(tax.total)}`}
                />
              </div>
            </CardContent>
          </Card>

          {/* ════════ 確定 / 通知 ════════ */}
          <Card>
            <CardHeader>
              <CardTitle as="h2">確定 / 通知</CardTitle>
              <CardDescription>
                審査内容を確定（署名）し、納税通知書を発付します。確定後は追記でのみ修正できます。
              </CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
              {/* 2人確認（maker-checker）: 確定の前提 */}
              <div>
                <h3 className="mb-2 inline-flex items-center gap-1.5 text-sm font-semibold text-foreground">
                  <IconUserCheck className="h-4 w-4" aria-hidden="true" />
                  2人確認（課税内容の照合）
                </h3>
                <CoSign
                  primaryId={officerId}
                  value={coSign}
                  requireReason={false}
                  attestations={[
                    { id: "income", label: "収入・控除の根拠資料を確認した" },
                    { id: "calc", label: "課税所得・税額の計算を照合した" },
                  ]}
                  signerLabel="確認者ID（係長・2人目）"
                  onSign={setCoSign}
                />
              </div>

              <Separator />

              {/* 署名・確定の監査記録（誰が・いつ） */}
              <SignedRecord
                value={record}
                onChange={setRecord}
                signerId={officerId}
                canSign={Boolean(coSign)}
                labels={{
                  draft: "未確定（下書き）",
                  signed: "課税確定済",
                  sign: "課税内容を確定",
                  signedByLabel: "確定者",
                  locked: "確定済みの課税内容は変更できません。更正は追記で記録します。",
                  addendaTitle: "更正・追記の記録",
                  addendum: "更正を追記",
                }}
              >
                {({ readOnly }) => (
                  <div className="rounded-md border border-border bg-muted/20 p-3 text-sm">
                    <p className="font-medium text-foreground">
                      令和6年度 市民税・県民税 課税決定
                    </p>
                    <p className="mt-1 text-muted-foreground tabular-nums">
                      年税額 {yen(tax.total)}（課税所得 {yen(tax.taxableIncome)}）
                    </p>
                    {!readOnly ? (
                      <p className="mt-2 text-xs text-muted-foreground">
                        {coSign
                          ? "2人確認が完了しました。確定できます。"
                          : "確定には上記の2人確認が必要です。"}
                      </p>
                    ) : null}
                  </div>
                )}
              </SignedRecord>

              {/* 納税通知書の発付（確定後のみ） */}
              {isFinalized ? (
                <>
                  <Separator />
                  <div className="flex items-center justify-between gap-3">
                    <div className="min-w-0">
                      <p className="text-sm font-medium text-foreground">納税通知書 / 納付書</p>
                      <p className="text-xs text-muted-foreground">
                        {noticeIssued
                          ? "発付済み。再発行は履歴に残ります。"
                          : "確定済みのため発付できます。"}
                      </p>
                    </div>
                    {noticeIssued ? (
                      <Badge variant="success" icon={<IconCircleCheck />}>
                        発付済み
                      </Badge>
                    ) : (
                      <Dialog>
                        <DialogTrigger asChild>
                          <Button variant="primary" size="sm">
                            <IconFileInvoice className="h-4 w-4" aria-hidden="true" />
                            通知書を発付
                          </Button>
                        </DialogTrigger>
                        <DialogContent>
                          <DialogHeader>
                            <DialogTitle>納税通知書を発付しますか？</DialogTitle>
                            <DialogDescription>
                              佐藤 健一 様（R-2024-0481）宛に、令和6年度 市民税・県民税の
                              納税通知書および期別納付書（年税額 {yen(tax.total)}）を発付します。
                            </DialogDescription>
                          </DialogHeader>
                          <dl className="rounded-md border border-border bg-muted/20 p-3 text-sm">
                            <div className="flex justify-between py-1">
                              <dt className="text-muted-foreground">確定者</dt>
                              <dd className="text-foreground">{officerId}</dd>
                            </div>
                            <div className="flex justify-between py-1">
                              <dt className="text-muted-foreground">確認者</dt>
                              <dd className="text-foreground">{coSign?.signerId ?? "—"}</dd>
                            </div>
                          </dl>
                          <DialogFooter>
                            <DialogClose asChild>
                              <Button variant="outline">キャンセル</Button>
                            </DialogClose>
                            <DialogClose asChild>
                              <Button
                                variant="primary"
                                onClick={() => setNoticeIssued(true)}
                              >
                                <IconFileInvoice className="h-4 w-4" aria-hidden="true" />
                                発付する
                              </Button>
                            </DialogClose>
                          </DialogFooter>
                        </DialogContent>
                      </Dialog>
                    )}
                  </div>
                </>
              ) : null}
            </CardContent>
          </Card>
        </div>
      </div>

      {/* ════════ 申告一覧（キュー） ════════ */}
      <section aria-labelledby="queue-heading" className="mt-8">
        <Card>
          <CardHeader>
            <CardTitle as="h2" id="queue-heading">
              申告一覧（審査キュー）
            </CardTitle>
            <CardDescription>
              申告区分・申告日・年税額・納付状況・SLA／未申告フラグ。行を選択すると審査画面へ移動します。
            </CardDescription>
          </CardHeader>
          <CardContent>
            <DataTable
              columns={columns}
              data={filings}
              pageSize={10}
              filter={{ columnId: "resident", placeholder: "住民名で絞り込み…" }}
              labels={{
                filterPlaceholder: "住民名で絞り込み…",
                noResults: "該当する申告はありません。",
                rowsPerPage: "表示件数",
                paginationSummary: (from, to, total) => `${total}件中 ${from}–${to}件`,
                pageSummary: (cur, total) => `${cur} / ${total} ページ`,
              }}
              onRowClick={(row) => {
                // 実システムでは該当住民の審査画面へ遷移。
                console.log("open filing", row.id);
              }}
              renderCard={(row) => (
                <div className="flex flex-col gap-2">
                  <div className="flex items-center justify-between gap-2">
                    <span className="font-medium text-foreground">{row.resident}</span>
                    {row.category === "未申告" ? (
                      <Badge variant="destructive" icon={<IconAlertTriangle />}>
                        未申告
                      </Badge>
                    ) : (
                      <Badge variant="outline">{row.category}</Badge>
                    )}
                  </div>
                  <div className="flex items-center justify-between text-sm text-muted-foreground tabular-nums">
                    <span>{row.id}</span>
                    <span>{row.taxAmount > 0 ? yen(row.taxAmount) : "—"}</span>
                  </div>
                </div>
              )}
            />
          </CardContent>
          <CardFooter className="justify-end">
            <Button variant="outline">CSV出力</Button>
          </CardFooter>
        </Card>
      </section>
    </main>
  );
}
